1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const isAlive = (count: number, wasAlive: boolean): boolean =>
15	  count === 3 || (count === 2 && wasAlive);
16	
17	export function nextGeneration(liveCells: Cell[]): Cell[] {
18	  const liveKeys = new Set(liveCells.map(cellKey));
19	  const tallies = new Map<string, { cell: Cell; count: number }>();
20	  for (const cell of liveCells.flatMap(neighborsOf)) {
21	    const key = cellKey(cell);
22	    const prev = tallies.get(key)?.count ?? 0;
23	    tallies.set(key, { cell, count: prev + 1 });
24	  }
25	  return [...tallies].flatMap(([key, { cell, count }]) =>
26	    isAlive(count, liveKeys.has(key)) ? [cell] : []
27	  );
28	}
