1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when input is empty", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 or 3 neighbors (survival)", () => {
15	    // vertical blinker: (0,0), (0,1), (0,2) — center (0,1) has 2 neighbors → survives
16	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
17	    expect(result).toContainEqual([0, 1]);
18	  });
19	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
20	    // Center (1,1) is surrounded by 8 neighbors → dies
21	    const result = nextGeneration([
22	      [0, 0], [1, 0], [2, 0],
23	      [0, 1], [1, 1], [2, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ]);
26	    expect(result).not.toContainEqual([1, 1]);
27	  });
28	  it("should bring a dead cell to life when it has exactly 3 neighbors (reproduction)", () => {
29	    // Dead cell (1,1) has exactly 3 live neighbors: (0,0), (1,0), (0,1)
30	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
31	    expect(result).toContainEqual([1, 1]);
32	  });
33	  it("should oscillate a vertical blinker to horizontal", () => {
34	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
35	    expect(result).toHaveLength(3);
36	    expect(result).toContainEqual([-1, 1]);
37	    expect(result).toContainEqual([0, 1]);
38	    expect(result).toContainEqual([1, 1]);
39	  });
40	  it("should keep a 2x2 block unchanged (still life)", () => {
41	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
42	    const result = nextGeneration(block);
43	    expect(result).toHaveLength(4);
44	    for (const cell of block) {
45	      expect(result).toContainEqual(cell);
46	    }
47	  });
48	  it("should handle negative coordinates", () => {
49	    // Vertical blinker shifted into negative space
50	    const result = nextGeneration([[-5, -5], [-5, -4], [-5, -3]]);
51	    expect(result).toHaveLength(3);
52	    expect(result).toContainEqual([-6, -4]);
53	    expect(result).toContainEqual([-5, -4]);
54	    expect(result).toContainEqual([-4, -4]);
